/*
===============================================================================
 CAP-COLLEGE DATABASE — CONTENT MIGRATION
-------------------------------------------------------------------------------
 Version      : 1.0.0
 File         : 11_import_french_6e.sql
 Purpose      : Import the corrected V5.1 bank and complete 6e French programme.
 Dependencies : 00_extensions.sql through 10_seed.sql
 Source        : Runtime order: data.js, V5.1/V5.2/V5.4 corrections, programme-v6.js
 Idempotent   : Yes, while no imported answer choice is referenced by student data.
===============================================================================

 Import summary
   - 4 curriculum domains
   - 40 provisional micro-skills to refine pedagogically
   - 590 stable question IDs (legacy_id 1 through 590)
   - 982 chronological question versions
   - 3,609 versioned answer choices

 Safety
   - The whole import runs in one transaction.
   - Imported questions remain `in_review`; they are not exposed to students.
   - Assertions at the end roll back everything if a total is inconsistent.
*/

begin;

create table if not exists public._cap_college_import_payload (
  singleton boolean primary key default true check (singleton),
  payload jsonb not null
);

alter table public._cap_college_import_payload enable row level security;
revoke all on public._cap_college_import_payload from anon, authenticated;

insert into public._cap_college_import_payload(singleton, payload)
values (true, $cap_college$
{"competencies":[{"code":"c_imperatif","domain":"Conjugaison","domain_code":"conjugation","name":"Impératif présent","lesson":"L’impératif exprime un ordre ou un conseil et s’emploie sans sujet exprimé."},{"code":"g_formes","domain":"Grammaire","domain_code":"grammar","name":"Formes de phrases","lesson":"Une phrase peut être affirmative ou négative, neutre ou exclamative."},{"code":"c_conditionnel","domain":"Conjugaison","domain_code":"conjugation","name":"Conditionnel présent","lesson":"Le conditionnel présent utilise le radical du futur et les terminaisons de l’imparfait."},{"code":"c_passe_simple","domain":"Conjugaison","domain_code":"conjugation","name":"Passé simple","lesson":"Le passé simple est un temps du récit écrit."},{"code":"c_pqp","domain":"Conjugaison","domain_code":"conjugation","name":"Plus-que-parfait","lesson":"Le plus-que-parfait se forme avec être ou avoir à l’imparfait et le participe passé."},{"code":"g_cc","domain":"Grammaire","domain_code":"grammar","name":"Compléments circonstanciels","lesson":"Un complément circonstanciel précise notamment le lieu, le temps ou la cause."},{"code":"g_attribut","domain":"Grammaire","domain_code":"grammar","name":"Attribut du sujet","lesson":"L’attribut caractérise le sujet après un verbe d’état."},{"code":"g_pronoms","domain":"Grammaire","domain_code":"grammar","name":"Pronoms personnels et antécédents","lesson":"Le pronom remplace un nom ou un groupe nominal appelé antécédent."},{"code":"g_propositions","domain":"Grammaire","domain_code":"grammar","name":"Propositions et articulation","lesson":"Les propositions peuvent être juxtaposées, coordonnées ou subordonnées."},{"code":"g_expansions","domain":"Grammaire","domain_code":"grammar","name":"Épithète et complément du nom","lesson":"L’épithète est un adjectif lié au nom ; le complément du nom est généralement un groupe prépositionnel."},{"code":"v_polysemie","domain":"Vocabulaire","domain_code":"vocabulary","name":"Polysémie","lesson":"Un mot polysémique possède plusieurs sens selon le contexte."},{"code":"v_formation","domain":"Vocabulaire","domain_code":"vocabulary","name":"Formation des mots","lesson":"Les mots peuvent être simples, dérivés par affixes ou composés."},{"code":"v_etymologie","domain":"Vocabulaire","domain_code":"vocabulary","name":"Étymologie","lesson":"L’étymologie étudie l’origine et l’évolution des mots."},{"code":"v_homonymes","domain":"Vocabulaire","domain_code":"vocabulary","name":"Homonymes","lesson":"Des homonymes se prononcent ou s’écrivent de la même façon mais ont des sens différents."},{"code":"v_registres","domain":"Vocabulaire","domain_code":"vocabulary","name":"Registres de langue","lesson":"On distingue notamment les registres familier, courant et soutenu."},{"code":"c_marques","domain":"Conjugaison","domain_code":"conjugation","name":"Radical et terminaisons","lesson":"Une forme verbale comprend un radical et une terminaison portant des marques de temps et de personne."},{"code":"c_valeurs","domain":"Conjugaison","domain_code":"conjugation","name":"Valeurs des temps","lesson":"Les temps situent les actions et peuvent exprimer durée, habitude ou action de premier plan."},{"code":"o_participe","domain":"Orthographe","domain_code":"spelling","name":"Accord du participe passé","lesson":"Avec être, le participe passé s’accorde avec le sujet ; avec avoir, il s’accorde avec le COD placé avant."},{"code":"o_feminin","domain":"Orthographe","domain_code":"spelling","name":"Féminin des noms et adjectifs","lesson":"Le féminin se forme régulièrement ou selon des formes particulières à mémoriser."},{"code":"o_lexicale","domain":"Orthographe","domain_code":"spelling","name":"Orthographe lexicale","lesson":"L’orthographe lexicale concerne l’écriture correcte des mots fréquents."},{"code":"c_imparfait","domain":"Conjugaison","domain_code":"conjugation","name":"Imparfait","lesson":"Terminaisons : -ais, -ais, -ait, -ions, -iez, -aient."},{"code":"c_present","domain":"Conjugaison","domain_code":"conjugation","name":"Présent de l’indicatif","lesson":"Vérifie la terminaison selon le sujet et le groupe du verbe."},{"code":"c_futur","domain":"Conjugaison","domain_code":"conjugation","name":"Futur simple","lesson":"On utilise généralement l’infinitif suivi de -ai, -as, -a, -ons, -ez, -ont."},{"code":"o_sujet_verbe","domain":"Orthographe","domain_code":"spelling","name":"Accord sujet-verbe","lesson":"Le verbe s’accorde toujours avec son sujet, même si les deux sont éloignés."},{"code":"c_passe_compose","domain":"Conjugaison","domain_code":"conjugation","name":"Passé composé","lesson":"Auxiliaire être ou avoir au présent + participe passé."},{"code":"g_sujet","domain":"Grammaire","domain_code":"grammar","name":"Sujet du verbe","lesson":"Pose la question « qui est-ce qui ? » avant le verbe."},{"code":"g_nature","domain":"Grammaire","domain_code":"grammar","name":"Nature des mots","lesson":"Repère le rôle du mot : déterminant devant un nom, adjectif pour préciser le nom, adverbe pour préciser un verbe ou un adjectif."},{"code":"g_cod","domain":"Grammaire","domain_code":"grammar","name":"COD","lesson":"Pose « qui ? » ou « quoi ? » après le verbe, sans préposition."},{"code":"g_phrase","domain":"Grammaire","domain_code":"grammar","name":"Phrase simple et complexe","lesson":"Une phrase simple contient un seul verbe conjugué ; une phrase complexe en contient plusieurs."},{"code":"g_types","domain":"Grammaire","domain_code":"grammar","name":"Types de phrases","lesson":"Déclarative : informe ; interrogative : questionne ; injonctive : ordonne ; exclamative : exprime une émotion."},{"code":"v_antonymes","domain":"Vocabulaire","domain_code":"vocabulary","name":"Antonymes","lesson":"Deux antonymes ont des sens opposés."},{"code":"v_synonymes","domain":"Vocabulaire","domain_code":"vocabulary","name":"Synonymes","lesson":"Deux synonymes ont un sens proche."},{"code":"v_familles","domain":"Vocabulaire","domain_code":"vocabulary","name":"Familles de mots","lesson":"Les mots d’une même famille ont un radical commun et un sens lié."},{"code":"g_coi","domain":"Grammaire","domain_code":"grammar","name":"COI","lesson":"Le COI complète le verbe avec une préposition, souvent à ou de."},{"code":"v_sens","domain":"Vocabulaire","domain_code":"vocabulary","name":"Sens propre et figuré","lesson":"Le sens propre est concret ; le sens figuré est imagé."},{"code":"o_et_est","domain":"Orthographe","domain_code":"spelling","name":"Homophones et / est","lesson":"Remplace « est » par « était ». Si cela fonctionne, écris « est »."},{"code":"o_a_a","domain":"Orthographe","domain_code":"spelling","name":"Homophones a / à","lesson":"Remplace « a » par « avait ». Si la phrase fonctionne, écris « a » ; sinon « à »."},{"code":"o_son_sont","domain":"Orthographe","domain_code":"spelling","name":"Homophones son / sont","lesson":"Remplace « sont » par « étaient ». Si cela fonctionne, écris « sont »."},{"code":"o_pluriel","domain":"Orthographe","domain_code":"spelling","name":"Pluriel des noms","lesson":"Attention aux pluriels particuliers : cheval/chevaux, jeu/jeux, journal/journaux."},{"code":"o_gn","domain":"Orthographe","domain_code":"spelling","name":"Accord dans le groupe nominal","lesson":"Déterminant, nom et adjectif s’accordent en genre et en nombre."}],"questions":[{"id":197,"competence_id":"o_sujet_verbe","difficulty":2,"versions":[{"version_number":1,"prompt":"Complète correctement : « La plupart des joueurs ___ arrivés. »","choices":["sont","est","était","sera"],"correct_index":0,"source_stage":"v5.1_base"}]},{"id":198,"competence_id":"o_sujet_verbe","difficulty":2,"versions":[{"version_number":1,"prompt":"Complète correctement : « Le groupe d’amis ___ en silence. »","choices":["avance","avancent","avances","avancer"],"correct_index":0,"source_stage":"v5.1_base"}]},{"id":195,"competence_id":"o_sujet_verbe","difficulty":2,"versions":[{"version_number":1,"prompt":"Complète correctement : « Ces histoires ___ intéressantes. »","choices":["sembles","semble","sembler","se