source_stage":"v5.1_base"},{"version_number":2,"prompt":"Dans « Le feu chauffe la maison. », l’expression est-elle employée au sens propre ou au sens figuré ?","choices":["Sens propre","Sens figuré"],"correct_index":0,"source_stage":"v5.2_corrections"}]},{"id":375,"competence_id":"v_sens","difficulty":2,"versions":[{"version_number":1,"prompt":"Dans « Son discours a semé le doute. », l’expression est-elle employée au sens propre ou au sens figuré ?","choices":["Propre","Figuré","Synonyme","Antonyme"],"correct_index":1,"source_stage":"v5.1_base"},{"version_number":2,"prompt":"Dans « Son discours a semé le doute. », l’expression est-elle employée au sens propre ou au sens figuré ?","choices":["Sens propre","Sens figuré"],"correct_index":1,"source_stage":"v5.2_corrections"}]},{"id":376,"competence_id":"v_sens","difficulty":2,"versions":[{"version_number":1,"prompt":"Dans « Le jardinier a semé des graines. », l’expression est-elle employée au sens propre ou au sens figuré ?","choices":["Propre","Figuré","Synonyme","Antonyme"],"correct_index":0,"source_stage":"v5.1_base"},{"version_number":2,"prompt":"Dans « Le jardinier a semé des graines. », l’expression est-elle employée au sens propre ou au sens figuré ?","choices":["Sens propre","Sens figuré"],"correct_index":0,"source_stage":"v5.2_corrections"}]},{"id":399,"competence_id":"g_attribut","difficulty":2,"versions":[{"version_number":1,"prompt":"Quel est l’attribut dans « Son père est un excellent cuisinier » ?","choices":["un excellent cuisinier","Son père","est","excellent"],"correct_index":0,"source_stage":"programme_6e_complet"}]},{"id":400,"competence_id":"g_attribut","difficulty":2,"versions":[{"version_number":1,"prompt":"Quel est l’attribut dans « Les feuilles deviennent jaunes » ?","choices":["Les feuilles","jaunes","deviennent","feuilles"],"correct_index":1,"source_stage":"programme_6e_complet"}]},{"id":397,"competence_id":"g_attribut","difficulty":2,"versions":[{"version_number":1,"prompt":"Quel est l’attribut dans « Le gagnant demeure modeste » ?","choices":["Le gagnant","demeure","modeste","gagnant"],"correct_index":2,"source_stage":"programme_6e_complet"}]},{"id":398,"competence_id":"g_attribut","difficulty":2,"versions":[{"version_number":1,"prompt":"Quel est l’attribut dans « Cette route semble dangereuse » ?","choices":["Cette route","semble","route","dangereuse"],"correct_index":3,"source_stage":"programme_6e_complet"}]},{"id":401,"competence_id":"g_cc","difficulty":1,"versions":[{"version_number":1,"prompt":"Dans « Demain, nous partirons », quel groupe indique le temps ?","choices":["Demain","nous","partirons","nous partirons"],"correct_index":0,"source_stage":"programme_6e_complet"}]},{"id":404,"competence_id":"g_cc","difficulty":1,"versions":[{"version_number":1,"prompt":"Dans « Chaque matin, elle court au parc », quel groupe indique le temps ?","choices":["elle","court","au parc","Chaque matin"],"correct_index":3,"source_stage":"programme_6e_complet"}]},{"id":405,"competence_id":"g_cc","difficulty":1,"versions":[{"version_number":1,"prompt":"Dans « Les enfants jouent dans la cour », quel groupe indique le lieu ?","choices":["dans la cour","Les enfants","jouent","la cour"],"correct_index":0,"source_stage":"programme_6e_complet"}]},{"id":402,"competence_id":"g_cc","difficulty":1,"versions":[{"version_number":1,"prompt":"Dans « Le chat dort sous la table », quel groupe indique le lieu ?","choices":["Le chat","sous la table","dort","la table"],"correct_index":1,"source_stage":"programme_6e_complet"}]},{"id":403,"competence_id":"g_cc","difficulty":1,"versions":[{"version_number":1,"prompt":"Dans « Il tremble à cause du froid », quel groupe indique la cause ?","choices":["Il","tremble","à cause du froid","du froid"],"correct_index":2,"source_stage":"programme_6e_complet"}]},{"id":390,"competence_id":"g_coi","difficulty":2,"versions":[{"version_number":1,"prompt":"Quel est le COI dans « Nous pensons à notre projet » ?","choices":["Nous","à notre projet","pensons","notre projet"],"correct_index":1,"source_stage":"programme_6e_complet"}]},{"id":391,"competence_id":"g_attribut","difficulty":1,"versions":[{"version_number":1,"prompt":"Quel est l’attribut du sujet dans « Le ciel devient sombre » ?","choices":["sombre","Le ciel","devient","ciel"],"correct_index":0,"source_stage":"programme_6e_complet"}]},{"id":388,"competence_id":"g_coi","difficulty":2,"versions":[{"version_number":1,"prompt":"Quel est le COI dans « Tu réponds au professeur » ?","choices":["Tu","réponds","le professeur","au professeur"],"correct_index":3,"source_stage":"programme_6e_complet"}]},{"id":389,"competence_id":"g_coi","difficulty":2,"versions":[{"version_number":1,"prompt":"Quel est le COI dans « Elle doute de sa réponse » ?","choices":["de sa réponse","Elle","doute","sa réponse"],"correct_index":0,"source_stage":"programme_6e_complet"}]},{"id":392,"competence_id":"g_attribut","difficulty":1,"versions":[{"version_number":1,"prompt":"Quel est l’attribut dans « Ma sœur est médecin » ?","choices":["Ma sœur","médecin","est","sœur"],"correct_index":1,"source_stage":"programme_6e_complet"}]},{"id":395,"competence_id":"g_attribut","difficulty":1,"versions":[{"version_number":1,"prompt":"Quel est l’attribut dans « Cette histoire paraît vraie » ?","choices":["vraie","Cette histoire","paraît","histoire"],"correct_index":0,"source_stage":"programme_6e_complet"}]},{"id":396,"competence_id":"g_attribut","difficulty":2,"versions":[{"version_number":1,"prompt":"Dans « Les enfants sont heureux », quel mot caractérise le sujet ?","choices":["Les enfants","heureux","sont","enfants"],"correct_index":1,"source_stage":"programme_6e_complet"}]},{"id":393,"competence_id":"g_attribut","difficulty":1,"versions":[{"version_number":1,"prompt":"Quel est l’attribut dans « Ces exercices semblent faciles » ?","choices":["Ces exercices","semblent","faciles","exercices"],"correct_index":2,"source_stage":"programme_6e_complet"}]},{"id":394,"competence_id":"g_attribut","difficulty":1,"versions":[{"version_number":1,"prompt":"Quel est l’attribut dans « Paul reste silencieux » ?","choices":["Paul","reste","silence","silencieux"],"correct_index":3,"source_stage":"programme_6e_complet"}]}]}
$cap_college$::jsonb)
on conflict (singleton) do update
set payload = excluded.payload;

-- Fail early if the reference seed was not installed.
do $block$
begin
  if not exists (select 1 from public.subjects where code = 'french') then
    raise exception 'Missing subject seed: french';
  end if;
  if not exists (select 1 from public.levels where code = '6e') then
    raise exception 'Missing level seed: 6e';
  end if;
end
$block$;

with competencies as (
  select competency.item
  from public._cap_college_import_payload p,
       jsonb_array_elements(p.payload -> 'competencies')
         as competency(item)
), unique_domains as (
  select distinct
    item ->> 'domain_code' as code,
    item ->> 'domain' as name
  from competencies
)
insert into public.domains (
  id, subject_id, code, name, description, sort_order, active
)
select
  md5('cap-college:domain:french:' || d.code)::uuid,
  s.id,
  d.code,
  d.name,
  'Domaine importé depuis la banque française de 6e.',
  row_number() over (order by d.name)::smallint,
  true
from unique_domains d
cross join public.subjects s
where s.code = 'french'
on conflict (subject_id, code) do update
set name = excluded.name,
    description = excluded.description,
    active = true;

with competencies as (
  select competency.item
  from public._cap_college_import_payload p,
       jsonb_array_elements(p.payload -> 'competencies')
         as competency(item)
)
insert into public.skills (
  id, domain_id, code, name, description, sort_order, active
)
select
  md5('cap-college:skill:' || (c.item ->> 'code'))::uuid,
  d.id,
  c.item ->> 'code',
  c.item ->> 'name',
  'Compétence historique importée ; son découpage atomique sera affiné.',
  row_number() over (
    partition by d.id order by c.item ->> 'name'
  )::smallint,
  true
from competencies c
join public.subjects s on s.code = 'french'
join public.domains d
  on d.subject_id = s.id
 and d.code = c.item ->> 'domain_code'
on conflict (domain_id, code) do update
set name = excluded.name,
    description = excluded.description,
    active = true;

with competencies as (
  select competency.item
  from public._cap_college_import_payload p,
       jsonb_array_elements(p.payload -> 'competencies')
         as competency(item)
)
insert into public.micro_skills (
  id,
  skill_id,
  code,
  teacher_name,
  student_name,
  description,
  lesson_reminder,
  sort_order,
  active
)
select
  md5('cap-college:micro-skill:' || (c.item ->> 'code'))::uuid,
  s.id,
  'legacy_' || (c.item ->> 'code'),
  c.item ->> 'name',
  c.item ->> 'name',
  'Micro-compétence provisoire issue de la banque historique ; à redécouper en automatismes atomiques.',
  nullif(c.item ->> 'lesson', ''),
  1,
  true
from competencies c
join public.skills s on s.code = c.item ->> 'code'
on conflict (code) do update
set teacher_name = excluded.teacher_name,
    student_name = excluded.student_name,
    description = excluded.description,
    lesson_reminder = excluded.lesson_reminder,
    active = true;

insert into public.micro_skill_levels (micro_skill_id, level_id, is_expected)
select ms.id, l.id, true
from public.micro_skills ms
cross join public.levels l
where ms.code like 'legacy_%'
  and l.code = '6e'
on conflict (micro_skill_id, level_id) do update
set is_expected = true;

with imported_questions as (
  select imported_question.item
  from public._cap_college_import_payload p,
       jsonb_array_elements(p.payload -> 'questions')
         as imported_question(item)
)
insert into public.questions (
  id,
  legacy_id,
  micro_skill_id,
  status,
  theoretical_difficulty,
  current_version_number,
  active
)
select
  md5('cap-college:question:' || (q.item ->> 'id'))::uuid,
  (q.item ->> 'id')::bigint,
  ms.id,
  'in_review'::public.question_status,
  (q.item ->> 'difficulty')::public.difficulty_level,
  jsonb_array_length(q.item -> 'versions'),
  true
from imported_questions q
join public.micro_skills ms
  on ms.code = 'legacy_' || (q.item ->> 'competence_id')
on conflict (legacy_id) do update
set micro_skill_id = excluded.micro_skill_id,
    status = 'in_review',
    theoretical_difficulty = excluded.theoretical_difficulty,
    current_version_number = excluded.current_version_number,
    active = true;

with imported_questions as (
  select imported_question.item
  from public._cap_college_import_payload p,
       jsonb_array_elements(p.payload -> 'questions')
         as imported_question(item)
), imported_versions as (
  select
    q.item as question_item,
    version_item
  from imported_questions q
  cross join lateral jsonb_array_elements(q.item -> 'versions')
    as imported_version(version_item)
)
insert into public.question_versions (
  id,
  question_id,
  version_number,
  prompt,
  correction_explanation,
  change_comment,
  review_status
)
select
  md5(
    'cap-college:question-version:'
    || (v.question_item ->> 'id') || ':'
    || (v.version_item ->> 'version_number')
  )::uuid,
  q.id,
  (v.version_item ->> 'version_number')::integer,
  v.version_item ->> 'prompt',
  ms.lesson_reminder,
  'Import automatique — étape source : '
    || (v.version_item ->> 'source_stage'),
  'unreviewed'::public.review_status
from imported_versions v
join public.questions q
  on q.legacy_id = (v.question_item ->> 'id')::bigint
join public.micro_skills ms on ms.id = q.micro_skill_id
on conflict (question_id, version_number) do update
set prompt = excluded.prompt,
    correction_explanation = excluded.correction_explanation,
    change_comment = excluded.change_comment;

-- Rebuild choices only for the imported versions. A foreign-key restriction
-- prevents accidental rebuilding after those choices have received answers.
delete from public.answer_choices ac
using public.question_versions qv, public.questions q
where ac.question_version_id = qv.id
  and qv.question_id = q.id
  and q.legacy_id between 1 and 590;

with imported_questions as (
  select imported_question.item
  from public._cap_college_import_payload p,
       jsonb_array_elements(p.payload -> 'questions')
         as imported_question(item)
), imported_versions as (
  select
    q.item as question_item,
    version_item
  from imported_questions q
  cross join lateral jsonb_array_elements(q.item -> 'versions')
    as imported_version(version_item)
), imported_choices as (
  select
    v.question_item,
    v.version_item,
    choice.content,
    choice.ordinality::integer as ordinal
  from imported_versions v
  cross join lateral jsonb_array_elements_text(
    v.version_item -> 'choices'
  ) with ordinality as choice(content, ordinality)
)
insert into public.answer_choices (
  id,
  question_version_id,
  choice_key,
  content,
  is_correct,
  sort_order
)
select
  md5(
    'cap-college:answer-choice:'
    || (c.question_item ->> 'id') || ':'
    || (c.version_item ->> 'version_number') || ':'
    || c.ordinal
  )::uuid,
  qv.id,
  chr(64 + c.ordinal),
  c.content,
  c.ordinal - 1 = (c.version_item ->> 'correct_index')::integer,
  c.ordinal::smallint
from imported_choices c
join public.questions q
  on q.legacy_id = (c.question_item ->> 'id')::bigint
join public.question_versions qv
  on qv.question_id = q.id
 and qv.version_number = (c.version_item ->> 'version_number')::integer;

-- Transactional integrity checks. Any mismatch aborts and rolls back the import.
do $block$
declare
  imported_question_count integer;
  imported_version_count integer;
  imported_choice_count integer;
  correct_choice_count integer;
begin
  select count(*) into imported_question_count
  from public.questions
  where legacy_id between 1 and 590;

  select count(*) into imported_version_count
  from public.question_versions qv
  join public.questions q on q.id = qv.question_id
  where q.legacy_id between 1 and 590;

  select count(*) into imported_choice_count
  from public.answer_choices ac
  join public.question_versions qv on qv.id = ac.question_version_id
  join public.questions q on q.id = qv.question_id
  where q.legacy_id between 1 and 590;

  select count(*) into correct_choice_count
  from public.answer_choices ac
  join public.question_versions qv on qv.id = ac.question_version_id
  join public.questions q on q.id = qv.question_id
  where q.legacy_id between 1 and 590
    and ac.is_correct;

  if imported_question_count <> 590 then
    raise exception 'Expected 590 questions, found %', imported_question_count;
  end if;
  if imported_version_count <> 982 then
    raise exception 'Expected 982 versions, found %', imported_version_count;
  end if;
  if imported_choice_count <> 3609 then
    raise exception 'Expected 3609 choices, found %', imported_choice_count;
  end if;
  if correct_choice_count <> 982 then
    raise exception 'Expected one correct choice per version (982), found %', correct_choice_count;
  end if;
end
$block$;

commit;
